(()=>{function e(e){fetch(e).then(e=>e.text()).then(e=>{let n=new DOMParser,t=n.parseFromString(e,"text/html");document.getElementById("main-content").innerHTML=t.getElementById("main-content").innerHTML,document.getElementsByTagName("title")[0].innerHTML=t.getElementsByTagName("title")[0].innerHTML,window.scrollTo(0,0)}).catch(e=>console.warn(e))}})()